INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('locality-814ced5a-moex-00146', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「在十八世紀的藝術語境，創造是指一種新奇的形式，而新奇的形式是從模仿概念中衍生出來的，所 謂『原創性』就是一種『對神聖的規則和傳統元素做出重新詮釋』。就像法國的洛可可風，吸納轉化 了中國元素，可以說是一種『創造性模仿』。所以，『創新』不是無中生有，不等於追逐新奇，而是『下 至陰間給已死的語言賦予聲音』。」 根據上文，下列選項正確的是：', '["十八世紀的藝術創作多半立足於模仿他人", "在傳統中尋找不同詮釋是創新的核心精神", "即使是原創性的作品也受到前人成果影響", "洛可可風是為了抵抗中國元素流行而產生 想創造新的藝術形式必須先複製古代名作"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00147', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「無所不在的麥當勞、肯德基炸雞、可樂、迪士尼樂園、好萊塢電影……，使所有地方千篇一律。世 界各地的特色正逐漸消失，各種文化的紋路一點一點被那隻『看不見的手』撫平。」 根據上文，「那隻看不見的手」可能是：', '["強勢文化的影響", "民粹思想的抗衡", "跨國企業的引入", "文化價值的定位 自由市場的機能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00148', 'locality-814ced5a', 'locality-814ced5a-moex-111-01c5eaab', 'sub-locality-814ced5a-03', NULL, 'single_choice', '「白兔連續三年獲得越野馬拉松冠軍，記者採訪時問他：請問你如何每年都獲得冠軍？有人說您有祖 傳食譜可以強化體力，有人說你的腿構造與眾不同，請問真相為何？兔子笑說：我得冠軍的原因很簡 單，我在賽前會觀察地形，記住什麼地方有一棵樹，什麼地方有小土堆，在比賽的時候，我就想：快 跑，跑到前面那棵樹，我就是冠軍了。每一站我都會這樣想。快跑不動的時候，我就想：後面有一隻 大野狼在追我，快跑！」 根據上述故事 ，白兔賽跑獲勝的原因包含：', '["天賦異稟", "事前蒐集資訊", "設定短期目標", "有營養飲食秘方 給自己些許壓力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:28+00:00", "source_pdf_sha1": "e90a507a577f", "answer_pdf_sha1": "69eb6bd30069", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00149', 'locality-814ced5a', 'locality-814ced5a-moex-111-c2172ccd', 'sub-locality-814ced5a-04', NULL, 'single_choice', '用於資料認證與安全性之詮釋資料（metadata），屬於下列何種功能類型？', '["描述型", "管理型", "保存型", "技術型"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "06c41d1d3d97", "answer_pdf_sha1": "0d76495f743f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0417", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
