  ('locality-814ced5a-moex-00151', 'locality-814ced5a', 'locality-814ced5a-moex-111-c2172ccd', 'sub-locality-814ced5a-04', NULL, 'single_choice', '美國的禁書週（BannedBookWeek）是何時？', '["每年9月的第一週", "每年9月的最後一週", "每年12月的第一週", "每年12月的最後一週"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "06c41d1d3d97", "answer_pdf_sha1": "0d76495f743f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0417", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
  ('locality-814ced5a-moex-00152', 'locality-814ced5a', 'locality-814ced5a-moex-111-c2172ccd', 'sub-locality-814ced5a-04', NULL, 'single_choice', '我國「醫學圖書館專業人員能力認證」是由下列那一個機構辦理？', '["國家圖書館", "中華民國圖書館學會", "臺灣醫學圖書館學會", "中華圖書資訊學教育學會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "06c41d1d3d97", "answer_pdf_sha1": "0d76495f743f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0417", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
