  ('locality-814ced5a-moex-00154', 'locality-814ced5a', 'locality-814ced5a-moex-111-c2172ccd', 'sub-locality-814ced5a-04', NULL, 'single_choice', '有一位學者歷年來發表了28 篇文章，但每篇文章的被引次數最高都不超過5次；另一位同領域學者歷年 來只發表過5篇文章，但每篇引用次數都超過28次。結果這兩位學者在某個指標上，通通都是獲得5。這 個指標是下列何者？', '["A指數", "G指數", "H指數", "Eigenfactor指數"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:29+00:00", "source_pdf_sha1": "06c41d1d3d97", "answer_pdf_sha1": "0d76495f743f", "source_family": "moex-gov-tw", "moex": {"exam_code": "111190", "c": "506", "s": "0417", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "圖書館學大意", "year": "111", "exam_name": "111年特種考試地方政府公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "圖書資訊管理"}'::jsonb, NULL),
